const body = $json.body || $json;
const evt = body.event;
const actor = body.actor || {};
const actorName = actor.name || 'Jemand';
const teamChannel = $env.SLACK_NOTIFY_CHANNEL || 'C0A7LTX603Z';

let emoji = '📋';
let text = '';
let targets = []; // {channel, text} pairs

switch(evt) {
  case 'aufgabe_zugewiesen': {
    emoji = '📋';
    const msg = `${emoji} *${actorName}* hat dir eine Aufgabe zugewiesen:\n> ${body.aufgabe || '?'}${body.prio ? ' (' + body.prio + ')' : ''}${body.dl ? ' — fällig: ' + body.dl : ''}`;
    // DM an die zugewiesene Person
    if (body.fuer?.slack_id) {
      targets.push({ channel: body.fuer.slack_id, text: msg });
    } else {
      // Fallback: Team-Channel
      targets.push({ channel: teamChannel, text: `${emoji} *${actorName}* hat *${body.fuer?.name || '?'}* eine Aufgabe zugewiesen:\n> ${body.aufgabe || '?'}${body.prio ? ' (' + body.prio + ')' : ''}${body.dl ? ' — fällig: ' + body.dl : ''}` });
    }
    break;
  }
  case 'meilenstein_erledigt': {
    emoji = '🎯';
    text = `${emoji} *${actorName}* hat einen Meilenstein erreicht! 🎉\n> ✅ *${body.meilenstein || '?'}*${body.ziel ? '\n> Ziel: ' + body.ziel : ''}`;
    // Celebration → Team-Channel
    targets.push({ channel: teamChannel, text });
    break;
  }
  case 'big3_erledigt': {
    emoji = '✅';
    text = `${emoji} *${actorName}* hat ein Big-3-Ziel erledigt (KW ${body.kw || '?'}):\n> ${body.big3 || '?'}`;
    // → Team-Channel
    targets.push({ channel: teamChannel, text });
    break;
  }
  case 'blocker': {
    emoji = '⚠️';
    const msg = `${emoji} *${actorName}* meldet einen Blocker:\n> ${body.blocker || '?'}`;
    // DM an jeden GF
    const gfIds = body.gf_slack_ids || [];
    if (gfIds.length) {
      gfIds.forEach(sid => targets.push({ channel: sid, text: msg }));
    } else {
      targets.push({ channel: teamChannel, text: msg });
    }
    break;
  }
  default:
    targets.push({ channel: teamChannel, text: `${actorName}: Unbekanntes Event (${evt})` });
}

return targets.map(t => ({ json: t }));
